CREATE OR REPLACE FUNCTION hr.post_absence_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_employee_id int := (p_data->>'employee_id')::int;
  v_date_debut date;
  v_date_fin date;
  v_nb_jours numeric;
  v_type text;
  v_balance numeric;
  v_warning text := '';
BEGIN
  IF v_employee_id IS NULL THEN
    RETURN pgv.toast('Salarié manquant.', 'error');
  END IF;

  v_date_debut := (p_data->>'date_debut')::date;
  v_date_fin := (p_data->>'date_fin')::date;
  v_nb_jours := (p_data->>'nb_jours')::numeric;
  v_type := COALESCE(NULLIF(trim(p_data->>'type_absence'), ''), 'conge_paye');

  IF v_date_debut IS NULL OR v_date_fin IS NULL OR v_nb_jours IS NULL THEN
    RETURN pgv.toast('Dates et nombre de jours obligatoires.', 'error');
  END IF;

  IF v_date_fin < v_date_debut THEN
    RETURN pgv.toast('La date de fin doit être après la date de début.', 'error');
  END IF;

  -- Check leave balance warning (CP, RTT only)
  IF v_type IN ('conge_paye', 'rtt') THEN
    SELECT (lb.allocated - lb.used) INTO v_balance
      FROM hr.leave_balance lb
     WHERE lb.employee_id = v_employee_id
       AND lb.leave_type = v_type;

    IF v_balance IS NOT NULL AND v_balance < v_nb_jours THEN
      v_warning := ' Attention : solde insuffisant (' || v_balance || 'j restants).';
    END IF;
  END IF;

  INSERT INTO hr.absence (employee_id, type_absence, date_debut, date_fin, nb_jours, motif)
  VALUES (
    v_employee_id,
    v_type,
    v_date_debut,
    v_date_fin,
    v_nb_jours,
    COALESCE(trim(p_data->>'motif'), '')
  );

  RETURN pgv.toast('Absence déclarée.' || v_warning)
    || pgv.redirect(pgv.call_ref('get_employee', jsonb_build_object('p_id', v_employee_id)));
END;
$function$;
COMMENT ON FUNCTION hr.post_absence_save(jsonb) IS 'Declare a new absence for an employee — warns if leave balance insufficient';

CREATE OR REPLACE FUNCTION hr.post_absence_validate(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'id')::int;
  v_action text := COALESCE(p_data->>'action', '');
  v_employee_id int;
  v_new_statut text;
  v_absence record;
  v_balance numeric;
BEGIN
  IF v_action = 'valider' THEN
    v_new_statut := 'validee';
  ELSIF v_action = 'refuser' THEN
    v_new_statut := 'refusee';
  ELSIF v_action = 'annuler' THEN
    v_new_statut := 'annulee';
  ELSE
    RETURN pgv.toast('Action invalide.', 'error');
  END IF;

  -- Fetch absence details before update
  SELECT a.employee_id, a.type_absence, a.nb_jours, a.statut
    INTO v_absence
    FROM hr.absence a WHERE a.id = v_id;

  IF v_absence IS NULL THEN
    RETURN pgv.toast('Absence introuvable.', 'error');
  END IF;

  IF v_absence.statut <> 'demande' THEN
    RETURN pgv.toast('Absence déjà traitée.', 'error');
  END IF;

  -- Check leave balance before validating (only for types with balance)
  IF v_action = 'valider' AND v_absence.type_absence IN ('conge_paye', 'rtt') THEN
    SELECT (lb.allocated - lb.used) INTO v_balance
      FROM hr.leave_balance lb
     WHERE lb.employee_id = v_absence.employee_id
       AND lb.leave_type = v_absence.type_absence;

    IF v_balance IS NOT NULL AND v_balance < v_absence.nb_jours THEN
      RETURN pgv.toast('Solde insuffisant : ' || v_balance || 'j restants sur ' || v_absence.nb_jours || 'j demandés.', 'error');
    END IF;
  END IF;

  -- Update absence status
  UPDATE hr.absence SET statut = v_new_statut
    WHERE id = v_id AND statut = 'demande'
    RETURNING employee_id INTO v_employee_id;

  IF NOT FOUND THEN
    RETURN pgv.toast('Absence introuvable ou déjà traitée.', 'error');
  END IF;

  -- Decrement leave balance on validation
  IF v_action = 'valider' THEN
    UPDATE hr.leave_balance
       SET used = used + v_absence.nb_jours
     WHERE employee_id = v_employee_id
       AND leave_type = v_absence.type_absence;
  END IF;

  RETURN pgv.toast('Absence ' || v_new_statut || '.')
    || pgv.redirect(pgv.call_ref('get_employee', jsonb_build_object('p_id', v_employee_id)));
END;
$function$;
COMMENT ON FUNCTION hr.post_absence_validate(jsonb) IS 'Validate, refuse or cancel an absence request — decrements leave balance on validation';

CREATE OR REPLACE FUNCTION hr.post_employee_delete(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'id')::int;
BEGIN
  DELETE FROM hr.employee WHERE id = v_id;
  IF NOT FOUND THEN
    RETURN pgv.toast('Salarié introuvable.', 'error');
  END IF;

  RETURN pgv.toast('Salarié supprimé.') || pgv.redirect(pgv.call_ref('get_index'));
END;
$function$;
COMMENT ON FUNCTION hr.post_employee_delete(jsonb) IS 'Delete an employee';

CREATE OR REPLACE FUNCTION hr.post_employee_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_nom text := trim(COALESCE(p_data->>'nom', ''));
  v_prenom text := trim(COALESCE(p_data->>'prenom', ''));
BEGIN
  IF v_nom = '' OR v_prenom = '' THEN
    RETURN pgv.toast('Nom et prénom obligatoires.', 'error');
  END IF;

  v_id := (p_data->>'id')::int;

  IF v_id IS NOT NULL THEN
    UPDATE hr.employee SET
      nom = v_nom,
      prenom = v_prenom,
      email = NULLIF(trim(COALESCE(p_data->>'email', '')), ''),
      phone = NULLIF(trim(COALESCE(p_data->>'phone', '')), ''),
      matricule = COALESCE(trim(p_data->>'matricule'), ''),
      date_naissance = (NULLIF(trim(COALESCE(p_data->>'date_naissance', '')), ''))::date,
      poste = COALESCE(trim(p_data->>'poste'), ''),
      departement = COALESCE(trim(p_data->>'departement'), ''),
      sexe = COALESCE(NULLIF(trim(p_data->>'sexe'), ''), ''),
      nationalite = COALESCE(trim(p_data->>'nationalite'), ''),
      qualification = COALESCE(trim(p_data->>'qualification'), ''),
      type_contrat = COALESCE(NULLIF(trim(p_data->>'type_contrat'), ''), 'cdi'),
      date_embauche = COALESCE((NULLIF(trim(p_data->>'date_embauche'), ''))::date, CURRENT_DATE),
      date_fin = (NULLIF(trim(COALESCE(p_data->>'date_fin', '')), ''))::date,
      heures_hebdo = COALESCE((NULLIF(trim(p_data->>'heures_hebdo'), ''))::numeric, 35),
      notes = COALESCE(trim(p_data->>'notes'), '')
    WHERE id = v_id;

    IF NOT FOUND THEN
      RETURN pgv.toast('Salarié introuvable.', 'error');
    END IF;

    RETURN pgv.toast('Salarié mis à jour.')
      || pgv.redirect(pgv.call_ref('get_employee', jsonb_build_object('p_id', v_id)));
  ELSE
    INSERT INTO hr.employee (nom, prenom, email, phone, matricule, date_naissance, sexe, nationalite, poste, departement, qualification, type_contrat, date_embauche, date_fin, heures_hebdo, notes)
    VALUES (
      v_nom, v_prenom,
      NULLIF(trim(COALESCE(p_data->>'email', '')), ''),
      NULLIF(trim(COALESCE(p_data->>'phone', '')), ''),
      COALESCE(trim(p_data->>'matricule'), ''),
      (NULLIF(trim(COALESCE(p_data->>'date_naissance', '')), ''))::date,
      COALESCE(NULLIF(trim(p_data->>'sexe'), ''), ''),
      COALESCE(trim(p_data->>'nationalite'), ''),
      COALESCE(trim(p_data->>'poste'), ''),
      COALESCE(trim(p_data->>'departement'), ''),
      COALESCE(trim(p_data->>'qualification'), ''),
      COALESCE(NULLIF(trim(p_data->>'type_contrat'), ''), 'cdi'),
      COALESCE((NULLIF(trim(p_data->>'date_embauche'), ''))::date, CURRENT_DATE),
      (NULLIF(trim(COALESCE(p_data->>'date_fin', '')), ''))::date,
      COALESCE((NULLIF(trim(p_data->>'heures_hebdo'), ''))::numeric, 35),
      COALESCE(trim(p_data->>'notes'), '')
    )
    RETURNING id INTO v_id;

    RETURN pgv.toast('Salarié créé.')
      || pgv.redirect(pgv.call_ref('get_employee', jsonb_build_object('p_id', v_id)));
  END IF;
END;
$function$;
COMMENT ON FUNCTION hr.post_employee_save(jsonb) IS 'Create or update an employee';

CREATE OR REPLACE FUNCTION hr.post_timesheet_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_employee_id int := (p_data->>'employee_id')::int;
  v_date date;
  v_heures numeric;
BEGIN
  IF v_employee_id IS NULL THEN
    RETURN pgv.toast('Salarié manquant.', 'error');
  END IF;

  v_date := (p_data->>'date_travail')::date;
  v_heures := (p_data->>'heures')::numeric;

  IF v_date IS NULL OR v_heures IS NULL THEN
    RETURN pgv.toast('Date et heures obligatoires.', 'error');
  END IF;

  IF v_heures < 0 OR v_heures > 24 THEN
    RETURN pgv.toast('Heures entre 0 et 24.', 'error');
  END IF;

  INSERT INTO hr.timesheet (employee_id, date_travail, heures, description)
  VALUES (v_employee_id, v_date, v_heures, COALESCE(trim(p_data->>'description'), ''))
  ON CONFLICT (employee_id, date_travail)
  DO UPDATE SET heures = EXCLUDED.heures, description = EXCLUDED.description;

  RETURN pgv.toast('Heures enregistrées.')
    || pgv.redirect(pgv.call_ref('get_employee', jsonb_build_object('p_id', v_employee_id)));
END;
$function$;
COMMENT ON FUNCTION hr.post_timesheet_save(jsonb) IS 'Save or update timesheet entry (upsert on employee+date)';

CREATE OR REPLACE FUNCTION hr.statut_variant(p_statut text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE p_statut
    WHEN 'actif' THEN 'success'
    WHEN 'inactif' THEN 'default'
    WHEN 'demande' THEN 'warning'
    WHEN 'validee' THEN 'success'
    WHEN 'refusee' THEN 'danger'
    WHEN 'annulee' THEN 'default'
    ELSE 'default'
  END;
$function$;
COMMENT ON FUNCTION hr.statut_variant(text) IS 'Badge variant for employee/absence status';

CREATE OR REPLACE FUNCTION hr.get_absences(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_statut text;
  v_type text;
  v_mois text;
  v_rows text[];
  v_body text;
  v_en_cours int;
  v_demandes int;
  v_total_mois int;
  r record;
BEGIN
  v_statut := NULLIF(trim(COALESCE(p_params->>'statut', '')), '');
  v_type := NULLIF(trim(COALESCE(p_params->>'type', '')), '');
  v_mois := NULLIF(trim(COALESCE(p_params->>'mois', '')), '');

  -- Stats
  SELECT count(*)::int INTO v_en_cours FROM hr.absence
    WHERE statut = 'validee' AND date_debut <= CURRENT_DATE AND date_fin >= CURRENT_DATE;
  SELECT count(*)::int INTO v_demandes FROM hr.absence WHERE statut = 'demande';
  SELECT count(*)::int INTO v_total_mois FROM hr.absence
    WHERE date_debut >= date_trunc('month', CURRENT_DATE) AND date_debut < date_trunc('month', CURRENT_DATE) + interval '1 month';

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('En cours', v_en_cours::text),
    pgv.stat('En attente', v_demandes::text),
    pgv.stat('Ce mois', v_total_mois::text)
  ]);

  -- Filters
  v_body := v_body || '<form><div class="grid">'
    || pgv.sel('statut', 'Statut', '[{"label":"Tous","value":""},{"label":"Demande","value":"demande"},{"label":"Validée","value":"validee"},{"label":"Refusée","value":"refusee"},{"label":"Annulée","value":"annulee"}]'::jsonb, COALESCE(v_statut, ''))
    || pgv.sel('type', 'Type', '[{"label":"Tous","value":""},{"label":"Congé payé","value":"conge_paye"},{"label":"RTT","value":"rtt"},{"label":"Maladie","value":"maladie"},{"label":"Sans solde","value":"sans_solde"},{"label":"Formation","value":"formation"},{"label":"Autre","value":"autre"}]'::jsonb, COALESCE(v_type, ''))
    || pgv.input('mois', 'month', 'Mois', v_mois)
    || '</div><button type="submit" class="secondary">Filtrer</button></form>';

  -- List
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, e.nom, e.prenom, e.id AS eid, a.type_absence, a.date_debut, a.date_fin, a.nb_jours, a.statut
      FROM hr.absence a
      JOIN hr.employee e ON e.id = a.employee_id
     WHERE (v_statut IS NULL OR a.statut = v_statut)
       AND (v_type IS NULL OR a.type_absence = v_type)
       AND (v_mois IS NULL OR to_char(a.date_debut, 'YYYY-MM') = v_mois)
     ORDER BY a.date_debut DESC
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s %s</a>', pgv.call_ref('get_employee', jsonb_build_object('p_id', r.eid)), pgv.esc(r.nom), pgv.esc(r.prenom)),
      hr.absence_label(r.type_absence),
      to_char(r.date_debut, 'DD/MM/YYYY'),
      to_char(r.date_fin, 'DD/MM/YYYY'),
      r.nb_jours::text || 'j',
      pgv.badge(upper(r.statut), hr.statut_variant(r.statut))
    ];
  END LOOP;

  IF cardinality(v_rows) = 0 THEN
    v_body := v_body || pgv.empty('Aucune absence trouvée.');
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY['Salarié', 'Type', 'Début', 'Fin', 'Jours', 'Statut'],
      v_rows,
      20
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION hr.get_absences(jsonb) IS 'Global absences list — all employees, filters by status/type/month';

CREATE OR REPLACE FUNCTION hr.get_employee(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_emp hr.employee;
  v_fiche text;
  v_absences text;
  v_heures text;
  v_body text;
  v_rows text[];
  r record;
  v_total_heures numeric;
  v_total_absences int;
  v_balance_stats text[];
  v_bal record;
BEGIN
  SELECT * INTO v_emp FROM hr.employee WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN pgv.alert('Salarié introuvable.', 'danger');
  END IF;

  -- Fiche
  v_fiche := pgv.dl(VARIADIC ARRAY[
    'Matricule', CASE WHEN v_emp.matricule = '' THEN '—' ELSE pgv.esc(v_emp.matricule) END,
    'Email', COALESCE(v_emp.email, '—'),
    'Téléphone', COALESCE(v_emp.phone, '—'),
    'Date de naissance', CASE WHEN v_emp.date_naissance IS NOT NULL THEN to_char(v_emp.date_naissance, 'DD/MM/YYYY') ELSE '—' END,
    'Sexe', CASE v_emp.sexe WHEN 'M' THEN 'Homme' WHEN 'F' THEN 'Femme' ELSE '—' END,
    'Nationalité', CASE WHEN v_emp.nationalite = '' THEN '—' ELSE pgv.esc(v_emp.nationalite) END,
    'Poste', CASE WHEN v_emp.poste = '' THEN '—' ELSE pgv.esc(v_emp.poste) END,
    'Département', CASE WHEN v_emp.departement = '' THEN '—' ELSE pgv.esc(v_emp.departement) END,
    'Qualification', CASE WHEN v_emp.qualification = '' THEN '—' ELSE pgv.esc(v_emp.qualification) END,
    'Contrat', hr.contrat_label(v_emp.type_contrat),
    'Embauche', to_char(v_emp.date_embauche, 'DD/MM/YYYY'),
    'Fin de contrat', CASE WHEN v_emp.date_fin IS NOT NULL THEN to_char(v_emp.date_fin, 'DD/MM/YYYY') ELSE '—' END,
    'Heures/semaine', v_emp.heures_hebdo::text || 'h',
    'Statut', pgv.badge(upper(v_emp.statut), hr.statut_variant(v_emp.statut)),
    'Notes', CASE WHEN v_emp.notes = '' THEN '—' ELSE pgv.esc(v_emp.notes) END
  ]);

  v_fiche := v_fiche || '<hr>'
    || pgv.form_dialog('dlg-edit-' || p_id,
      'Modifier ' || pgv.esc(v_emp.prenom) || ' ' || pgv.esc(v_emp.nom),
      hr._employee_form_body(v_emp),
      'post_employee_save',
      'Modifier', 'outline') || ' '
    || pgv.action('post_employee_delete', 'Supprimer', jsonb_build_object('id', p_id), 'Supprimer définitivement ce salarié et tout son historique ?', 'danger');

  -- Leave balance stats
  v_balance_stats := ARRAY[]::text[];
  FOR v_bal IN
    SELECT lb.leave_type, lb.allocated, lb.used, (lb.allocated - lb.used) AS remaining
      FROM hr.leave_balance lb
     WHERE lb.employee_id = p_id
     ORDER BY lb.leave_type
  LOOP
    v_balance_stats := v_balance_stats || pgv.stat(
      hr.absence_label(v_bal.leave_type),
      v_bal.remaining::text || 'j / ' || v_bal.allocated::text || 'j',
      CASE WHEN v_bal.remaining <= 0 THEN 'danger' WHEN v_bal.remaining <= 3 THEN 'warning' ELSE NULL END
    );
  END LOOP;

  -- Absences
  v_rows := ARRAY[]::text[];
  SELECT count(*)::int INTO v_total_absences FROM hr.absence WHERE employee_id = p_id;

  FOR r IN
    SELECT a.id, a.type_absence, a.date_debut, a.date_fin, a.nb_jours, a.motif, a.statut
      FROM hr.absence a
     WHERE a.employee_id = p_id
     ORDER BY a.date_debut DESC
  LOOP
    v_rows := v_rows || ARRAY[
      hr.absence_label(r.type_absence),
      to_char(r.date_debut, 'DD/MM/YYYY'),
      to_char(r.date_fin, 'DD/MM/YYYY'),
      r.nb_jours::text || 'j',
      pgv.badge(upper(r.statut), hr.statut_variant(r.statut)),
      CASE WHEN r.statut = 'demande' THEN
        pgv.action('post_absence_validate', 'Valider', jsonb_build_object('id', r.id, 'action', 'valider'))
        || ' ' || pgv.action('post_absence_validate', 'Refuser', jsonb_build_object('id', r.id, 'action', 'refuser'), NULL, 'danger')
      ELSE '—' END
    ];
  END LOOP;

  IF cardinality(v_balance_stats) > 0 THEN
    v_absences := pgv.grid(VARIADIC v_balance_stats);
  ELSE
    v_absences := '';
  END IF;

  IF v_total_absences = 0 THEN
    v_absences := v_absences || pgv.empty('Aucune absence enregistrée');
  ELSE
    v_absences := v_absences || pgv.md_table(
      ARRAY['Type', 'Début', 'Fin', 'Jours', 'Statut', 'Actions'],
      v_rows,
      10
    );
  END IF;

  v_absences := v_absences ||
    pgv.accordion(VARIADIC ARRAY[
      'Déclarer une absence',
      pgv.form('post_absence_save',
        '<input type="hidden" name="employee_id" value="' || p_id || '">'
        || pgv.sel('type_absence', 'Type', '[{"label":"Congé payé","value":"conge_paye"},{"label":"RTT","value":"rtt"},{"label":"Maladie","value":"maladie"},{"label":"Sans solde","value":"sans_solde"},{"label":"Formation","value":"formation"},{"label":"Autre","value":"autre"}]'::jsonb, 'conge_paye')
        || '<div class="grid">'
        || pgv.input('date_debut', 'date', 'Date début', NULL, true)
        || pgv.input('date_fin', 'date', 'Date fin', NULL, true)
        || pgv.input('nb_jours', 'number', 'Nb jours', NULL, true)
        || '</div>'
        || pgv.input('motif', 'text', 'Motif'),
        'Déclarer')
    ]);

  -- Heures (30 derniers jours)
  v_rows := ARRAY[]::text[];
  SELECT COALESCE(sum(t.heures), 0) INTO v_total_heures FROM hr.timesheet t
    WHERE t.employee_id = p_id AND t.date_travail >= CURRENT_DATE - 30;

  FOR r IN
    SELECT t.date_travail, t.heures, t.description
      FROM hr.timesheet t
     WHERE t.employee_id = p_id
     ORDER BY t.date_travail DESC
     LIMIT 30
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.date_travail, 'DD/MM/YYYY'),
      r.heures::text || 'h',
      COALESCE(NULLIF(r.description, ''), '—')
    ];
  END LOOP;

  IF cardinality(v_rows) = 0 THEN
    v_heures := pgv.empty('Aucune heure saisie');
  ELSE
    v_heures := pgv.grid(VARIADIC ARRAY[
      pgv.stat('Heures (30j)', v_total_heures::text || 'h')
    ])
    || pgv.md_table(ARRAY['Date', 'Heures', 'Description'], v_rows, 10);
  END IF;

  v_heures := v_heures ||
    pgv.accordion(VARIADIC ARRAY[
      'Saisir des heures',
      pgv.form('post_timesheet_save',
        '<input type="hidden" name="employee_id" value="' || p_id || '">'
        || '<div class="grid">'
        || pgv.input('date_travail', 'date', 'Date', to_char(CURRENT_DATE, 'YYYY-MM-DD'), true)
        || pgv.input('heures', 'number', 'Heures', NULL, true)
        || '</div>'
        || pgv.input('description', 'text', 'Description'),
        'Enregistrer')
    ]);

  v_body := pgv.breadcrumb(VARIADIC ARRAY['Salariés', pgv.call_ref('get_index'), v_emp.prenom || ' ' || v_emp.nom])
    || pgv.tabs(VARIADIC ARRAY['Fiche', v_fiche, 'Absences (' || v_total_absences || ')', v_absences, 'Heures', v_heures]);

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION hr.get_employee(integer) IS 'Employee detail page — fiche, absences with leave balance, timesheet tabs';

CREATE OR REPLACE FUNCTION hr.get_index(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_q text;
  v_statut text;
  v_contrat text;
  v_dept text;
  v_total int;
  v_actifs int;
  v_absences_en_cours int;
  v_rows text[];
  v_body text;
  r record;
BEGIN
  -- Extract filters
  v_q := NULLIF(trim(COALESCE(p_params->>'q', '')), '');
  v_statut := NULLIF(trim(COALESCE(p_params->>'statut', '')), '');
  v_contrat := NULLIF(trim(COALESCE(p_params->>'contrat', '')), '');
  v_dept := NULLIF(trim(COALESCE(p_params->>'dept', '')), '');

  -- Stats
  SELECT count(*)::int INTO v_total FROM hr.employee;
  SELECT count(*)::int INTO v_actifs FROM hr.employee WHERE statut = 'actif';
  SELECT count(*)::int INTO v_absences_en_cours FROM hr.absence
    WHERE statut = 'validee' AND date_debut <= CURRENT_DATE AND date_fin >= CURRENT_DATE;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Total salariés', v_total::text),
    pgv.stat('Actifs', v_actifs::text),
    pgv.stat('En absence', v_absences_en_cours::text)
  ]);

  -- Search/filter form
  v_body := v_body
    || '<form>'
    || '<div class="grid">'
    || pgv.input('q', 'search', 'Recherche nom/poste', v_q)
    || pgv.sel('statut', 'Statut', '[{"label":"Tous","value":""},{"label":"Actif","value":"actif"},{"label":"Inactif","value":"inactif"}]'::jsonb, COALESCE(v_statut, ''))
    || pgv.sel('contrat', 'Contrat', '[{"label":"Tous","value":""},{"label":"CDI","value":"cdi"},{"label":"CDD","value":"cdd"},{"label":"Alternance","value":"alternance"},{"label":"Stage","value":"stage"},{"label":"Intérim","value":"interim"}]'::jsonb, COALESCE(v_contrat, ''))
    || pgv.input('dept', 'text', 'Département', v_dept)
    || '</div>'
    || '<button type="submit" class="secondary">Filtrer</button>'
    || '</form>';

  -- Employee list
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT e.id, e.nom, e.prenom, e.poste, e.departement,
           e.type_contrat, e.date_embauche, e.statut
      FROM hr.employee e
     WHERE (v_q IS NULL OR e.nom ILIKE '%' || v_q || '%' OR e.prenom ILIKE '%' || v_q || '%' OR e.poste ILIKE '%' || v_q || '%')
       AND (v_statut IS NULL OR e.statut = v_statut)
       AND (v_contrat IS NULL OR e.type_contrat = v_contrat)
       AND (v_dept IS NULL OR e.departement ILIKE '%' || v_dept || '%')
     ORDER BY e.nom, e.prenom
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s %s</a>', pgv.call_ref('get_employee', jsonb_build_object('p_id', r.id)), pgv.esc(r.nom), pgv.esc(r.prenom)),
      COALESCE(NULLIF(r.poste, ''), '—'),
      COALESCE(NULLIF(r.departement, ''), '—'),
      hr.contrat_label(r.type_contrat),
      to_char(r.date_embauche, 'DD/MM/YYYY'),
      pgv.badge(upper(r.statut), hr.statut_variant(r.statut))
    ];
  END LOOP;

  IF v_total = 0 THEN
    v_body := v_body || pgv.empty('Aucun salarié', 'Ajoutez votre premier salarié pour commencer.');
  ELSIF cardinality(v_rows) = 0 THEN
    v_body := v_body || pgv.empty('Aucun résultat pour ces filtres.');
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY['Salarié', 'Poste', 'Département', 'Contrat', 'Embauche', 'Statut'],
      v_rows,
      20
    );
  END IF;

  v_body := v_body || pgv.form_dialog('dlg-new-employee',
    'Nouveau salarié',
    hr._employee_form_body(),
    'post_employee_save');

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION hr.get_index(jsonb) IS 'HR dashboard — stats, search/filters, employee list';

GRANT USAGE ON SCHEMA hr TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA hr TO web_anon;

-- Schema: hr_ut
CREATE SCHEMA IF NOT EXISTS hr_ut;

CREATE OR REPLACE FUNCTION hr_ut.test_absence_workflow()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
  v_emp_id int;
  v_abs_id int;
  v_used numeric;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  -- Setup: create employee
  INSERT INTO hr.employee (nom, prenom) VALUES ('Test', 'Absence') RETURNING id INTO v_emp_id;

  -- Declare absence
  v_result := hr.post_absence_save(jsonb_build_object(
    'employee_id', v_emp_id, 'type_absence', 'conge_paye',
    'date_debut', '2026-04-01', 'date_fin', '2026-04-05', 'nb_jours', 5
  ));
  RETURN NEXT ok(v_result LIKE '%déclarée%', 'absence declared');

  SELECT id INTO v_abs_id FROM hr.absence WHERE employee_id = v_emp_id;
  RETURN NEXT ok(v_abs_id IS NOT NULL, 'absence inserted');
  RETURN NEXT is((SELECT statut FROM hr.absence WHERE id = v_abs_id), 'demande', 'initial status is demande');

  -- Validate
  v_result := hr.post_absence_validate(jsonb_build_object('id', v_abs_id, 'action', 'valider'));
  RETURN NEXT ok(v_result LIKE '%validee%', 'validate returns success');
  RETURN NEXT is((SELECT statut FROM hr.absence WHERE id = v_abs_id), 'validee', 'status updated to validee');

  -- Cannot validate again
  v_result := hr.post_absence_validate(jsonb_build_object('id', v_abs_id, 'action', 'refuser'));
  RETURN NEXT ok(v_result LIKE '%déjà traitée%', 'double validation rejected');

  -- Validation errors
  v_result := hr.post_absence_save(jsonb_build_object(
    'employee_id', v_emp_id, 'type_absence', 'rtt',
    'date_debut', '2026-04-10', 'date_fin', '2026-04-05', 'nb_jours', 3
  ));
  RETURN NEXT ok(v_result LIKE '%après la date%', 'date_fin < date_debut rejected');

  -- Leave balance: setup balance for employee
  DELETE FROM hr.absence WHERE employee_id = v_emp_id;
  INSERT INTO hr.leave_balance (employee_id, leave_type, allocated, used)
    VALUES (v_emp_id, 'conge_paye', 25, 0);

  -- Declare + validate: should decrement used
  v_result := hr.post_absence_save(jsonb_build_object(
    'employee_id', v_emp_id, 'type_absence', 'conge_paye',
    'date_debut', '2026-06-01', 'date_fin', '2026-06-05', 'nb_jours', 5
  ));
  SELECT id INTO v_abs_id FROM hr.absence WHERE employee_id = v_emp_id AND date_debut = '2026-06-01';
  v_result := hr.post_absence_validate(jsonb_build_object('id', v_abs_id, 'action', 'valider'));
  SELECT used INTO v_used FROM hr.leave_balance WHERE employee_id = v_emp_id AND leave_type = 'conge_paye';
  RETURN NEXT is(v_used, 5::numeric, 'balance decremented after validation');

  -- Declare with insufficient balance: should warn
  UPDATE hr.leave_balance SET allocated = 25, used = 23 WHERE employee_id = v_emp_id AND leave_type = 'conge_paye';
  v_result := hr.post_absence_save(jsonb_build_object(
    'employee_id', v_emp_id, 'type_absence', 'conge_paye',
    'date_debut', '2026-07-01', 'date_fin', '2026-07-05', 'nb_jours', 5
  ));
  RETURN NEXT ok(v_result LIKE '%insuffisant%', 'warning on insufficient balance at declaration');

  -- Validate with insufficient balance: should block
  SELECT id INTO v_abs_id FROM hr.absence WHERE employee_id = v_emp_id AND date_debut = '2026-07-01';
  v_result := hr.post_absence_validate(jsonb_build_object('id', v_abs_id, 'action', 'valider'));
  RETURN NEXT ok(v_result LIKE '%insuffisant%', 'validation blocked on insufficient balance');
  RETURN NEXT is((SELECT statut FROM hr.absence WHERE id = v_abs_id), 'demande', 'absence stays demande when balance insufficient');

  -- Cleanup
  DELETE FROM hr.leave_balance WHERE employee_id = v_emp_id;
  DELETE FROM hr.absence WHERE employee_id = v_emp_id;
  DELETE FROM hr.employee WHERE id = v_emp_id;
END;
$function$;
COMMENT ON FUNCTION hr_ut.test_absence_workflow() IS 'Unit test: absence declaration, validation workflow, and leave balance';

CREATE OR REPLACE FUNCTION hr_ut.test_employee_crud()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
  v_id int;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  -- Create
  v_result := hr.post_employee_save(jsonb_build_object(
    'nom', 'Dupont', 'prenom', 'Jean', 'email', 'jean@test.com',
    'poste', 'Développeur', 'departement', 'IT', 'type_contrat', 'cdi'
  ));
  RETURN NEXT ok(v_result LIKE '%Salarié créé%', 'create employee returns success toast');

  SELECT id INTO v_id FROM hr.employee WHERE nom = 'Dupont' AND prenom = 'Jean';
  RETURN NEXT ok(v_id IS NOT NULL, 'employee inserted in DB');

  -- Read
  v_result := hr.get_employee(v_id);
  RETURN NEXT ok(v_result LIKE '%Dupont%', 'get_employee contains name');
  RETURN NEXT ok(v_result LIKE '%Développeur%', 'get_employee contains poste');
  RETURN NEXT ok(v_result LIKE '%CDI%', 'get_employee contains contract type');

  -- Update
  v_result := hr.post_employee_save(jsonb_build_object(
    'id', v_id, 'nom', 'Dupont', 'prenom', 'Jean',
    'poste', 'Lead Dev', 'departement', 'IT', 'type_contrat', 'cdi'
  ));
  RETURN NEXT ok(v_result LIKE '%mis à jour%', 'update employee returns success toast');
  RETURN NEXT ok((SELECT poste FROM hr.employee WHERE id = v_id) = 'Lead Dev', 'poste updated in DB');

  -- Delete
  v_result := hr.post_employee_delete(jsonb_build_object('id', v_id));
  RETURN NEXT ok(v_result LIKE '%supprimé%', 'delete returns success toast');
  RETURN NEXT ok(NOT EXISTS(SELECT 1 FROM hr.employee WHERE id = v_id), 'employee deleted from DB');

  -- Validation
  v_result := hr.post_employee_save(jsonb_build_object('nom', '', 'prenom', ''));
  RETURN NEXT ok(v_result LIKE '%obligatoires%', 'empty name/prenom rejected');
END;
$function$;
COMMENT ON FUNCTION hr_ut.test_employee_crud() IS 'Unit test: employee CRUD operations';

CREATE OR REPLACE FUNCTION hr_ut.test_timesheet()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_result text;
  v_emp_id int;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  -- Setup
  INSERT INTO hr.employee (nom, prenom) VALUES ('Test', 'Heures') RETURNING id INTO v_emp_id;

  -- Save timesheet
  v_result := hr.post_timesheet_save(jsonb_build_object(
    'employee_id', v_emp_id, 'date_travail', '2026-03-10', 'heures', 8, 'description', 'Dev feature X'
  ));
  RETURN NEXT ok(v_result LIKE '%enregistrées%', 'timesheet saved');
  RETURN NEXT is(
    (SELECT heures FROM hr.timesheet WHERE employee_id = v_emp_id AND date_travail = '2026-03-10'),
    8::numeric, 'hours stored correctly'
  );

  -- Upsert (same date)
  v_result := hr.post_timesheet_save(jsonb_build_object(
    'employee_id', v_emp_id, 'date_travail', '2026-03-10', 'heures', 7.5, 'description', 'Updated'
  ));
  RETURN NEXT ok(v_result LIKE '%enregistrées%', 'upsert works');
  RETURN NEXT is(
    (SELECT heures FROM hr.timesheet WHERE employee_id = v_emp_id AND date_travail = '2026-03-10'),
    7.5::numeric, 'hours updated via upsert'
  );
  RETURN NEXT is(
    (SELECT count(*)::int FROM hr.timesheet WHERE employee_id = v_emp_id AND date_travail = '2026-03-10'),
    1, 'only one row per employee+date'
  );

  -- Validation
  v_result := hr.post_timesheet_save(jsonb_build_object(
    'employee_id', v_emp_id, 'date_travail', '2026-03-11', 'heures', 25
  ));
  RETURN NEXT ok(v_result LIKE '%entre 0 et 24%', 'hours > 24 rejected');

  -- Cleanup
  DELETE FROM hr.timesheet WHERE employee_id = v_emp_id;
  DELETE FROM hr.employee WHERE id = v_emp_id;
END;
$function$;
COMMENT ON FUNCTION hr_ut.test_timesheet() IS 'Unit test: timesheet save and upsert';

GRANT USAGE ON SCHEMA hr_ut TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA hr_ut TO web_anon;

